import{_ as a,o as t,c as d,a4 as n}from"./chunks/framework.Cqne-ChA.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-remove.md","filePath":"reference/zopen-remove.md","lastUpdated":1776692264000}'),r={name:"reference/zopen-remove.md"};function o(p,e,f,c,i,m){return t(),d("div",null,[...e[0]||(e[0]=[n('<div class="man-page-content" data-v-cfe27d00><h1 align="center" data-v-cfe27d00>ZOPEN-REMOVE</h1><h2 data-v-cfe27d00>NAME <a name="NAME" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00>zopen-remove − manual page for zopen-remove 0.8.4</p><h2 data-v-cfe27d00>SYNOPSIS <a name="SYNOPSIS" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00><b data-v-cfe27d00>zopen-remove</b> [<i data-v-cfe27d00>OPTION</i>] [<i data-v-cfe27d00>PACKAGE</i>] ...</p><h2 data-v-cfe27d00>DESCRIPTION <a name="DESCRIPTION" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00>zopen−remove is a utility for zopen community to remove an installed package or packages.</p><h2 data-v-cfe27d00>OPTIONS <a name="OPTIONS" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00><b data-v-cfe27d00>−h</b>, <b data-v-cfe27d00>−−help</b>, −?</p><p style="margin-left:22%;" data-v-cfe27d00>display this help and exit.</p><p style="margin-left:11%;" data-v-cfe27d00><b data-v-cfe27d00>−p</b>, <b data-v-cfe27d00>−−purge</b></p><p style="margin-left:22%;" data-v-cfe27d00>remove package, the versioned directory, and any cached files.</p><p style="margin-left:11%;" data-v-cfe27d00><b data-v-cfe27d00>−v</b>, <b data-v-cfe27d00>−−verbose</b></p><p style="margin-left:22%;" data-v-cfe27d00>run in verbose mode.</p><p style="margin-left:11%;" data-v-cfe27d00><b data-v-cfe27d00>−−version</b></p><p style="margin-left:22%;" data-v-cfe27d00>print version.</p><p style="margin-left:11%;" data-v-cfe27d00><b data-v-cfe27d00>−y</b>, <b data-v-cfe27d00>−−yes</b></p><p style="margin-left:22%;" data-v-cfe27d00>automatically answer yes to prompts.</p><h2 data-v-cfe27d00>EXAMPLES <a name="EXAMPLES" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00>zopen remove foo bar</p><p style="margin-left:22%;" data-v-cfe27d00>interactively remove the foo and bar packages if installed</p><p style="margin-left:11%;" data-v-cfe27d00>zopen remove −−yes foo bar</p><p style="margin-left:22%;" data-v-cfe27d00>remove the foo and bar packages if installed, without asking for confirmation</p><h2 data-v-cfe27d00>AUTHOR <a name="AUTHOR" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00>Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p><h2 data-v-cfe27d00>REPORTING BUGS <a name="REPORTING BUGS" data-v-cfe27d00></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00>Report bugs at https://github.com/zopencommunity/meta/issues .</p><p style="margin-left:11%;margin-top:1em;" data-v-cfe27d00>This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE−2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p></div>',1)])])}const l=a(r,[["render",o],["__scopeId","data-v-cfe27d00"]]);export{v as __pageData,l as default};
